import Sidebar from "../components/Sidebar";

function AnalyticsPage() {

  return (

    <>

      <Sidebar />

      <div style={{ marginLeft: "240px", padding: "30px" }}>

        <h1>Exit Analytics Dashboard</h1>

        <div
          style={{
            display: "flex",
            gap: "20px",
            marginTop: "30px",
          }}
        >

          <div
            style={{
              border: "1px solid black",
              padding: "20px",
              width: "220px",
              borderRadius: "10px",
            }}
          >
            <h2>Total Resignations</h2>
            <h1>12</h1>
          </div>

          <div
            style={{
              border: "1px solid black",
              padding: "20px",
              width: "220px",
              borderRadius: "10px",
            }}
          >
            <h2>Approved Clearances</h2>
            <h1>8</h1>
          </div>

          <div
            style={{
              border: "1px solid black",
              padding: "20px",
              width: "220px",
              borderRadius: "10px",
            }}
          >
            <h2>Returned Assets</h2>
            <h1>6</h1>
          </div>

        </div>

      </div>

    </>
  );
}

export default AnalyticsPage;
